3	import "strings"
4	
5	// DiffFile is one file's slice of a unified diff. Stat is the
6	// "+N -N" or "Bin" summary line; HunkHeaders are the "@@ ..." lines
7	// in original order; Body is the full per-file diff text including
8	// the "diff --git" header.
9	type DiffFile struct {
10		Path        string
11		Stat        string
12		HunkHeaders []string
13		Body        string
14	}
15	
16	// DecomposeDiff parses a unified diff into per-file slices. It supports
17	// the standard "diff --git a/<path> b/<path>" delimiter produced by
18	// git. Files that lack a parseable header are returned with an empty
19	// Path. The returned slice preserves input order.
20	//
21	// FEAT-022 §1: diff decomposer returns file inventory, per-file stat
22	// lines, and hunk headers so large diffs can degrade to
23	// stat + hunk-headers only.
24	func DecomposeDiff(diff string) []DiffFile {
25		if diff == "" {
26			return nil
27		}
28		lines := strings.Split(diff, "\n")
29		var files []DiffFile
30		var cur *DiffFile
31	
32		flush := func() {
33			if cur != nil {
34				files = append(files, *cur)
35				cur = nil
36			}
37		}
38	
39		for i, line := range lines {
40			if strings.HasPrefix(line, "diff --git ") {
41				flush()
42				path := parseDiffGitPath(line)
43				cur = &DiffFile{Path: path}
44			}
45			if cur == nil {
46				continue
47			}
48			// Append line to body (preserve trailing newlines except final empty).
49			if i < len(lines)-1 {
50				cur.Body += line + "\n"
51			} else {
52				cur.Body += line
53			}
54			switch {
55			case strings.HasPrefix(line, "@@ "):
56				cur.HunkHeaders = append(cur.HunkHeaders, line)
57			case strings.HasPrefix(line, "Binary files "):
58				cur.Stat = "Bin"
59			}
60		}
61		flush()
62		return files
63	}
64	
65	func parseDiffGitPath(header string) string {
66		// "diff --git a/<path> b/<path>"
67		rest := strings.TrimPrefix(header, "diff --git ")
68		parts := strings.SplitN(rest, " ", 2)
69		if len(parts) == 0 {
70			return ""
71		}
72		a := parts[0]
73		a = strings.TrimPrefix(a, "a/")
74		return a
75	}
76	
77	// ClampDiff bounds a unified diff to max bytes. When the diff fits, it
78	// returns the diff unchanged. When it does not, it degrades each file
79	// to "stat + hunk headers only" in input order until the budget is
80	// reached, then truncates the remainder. Files that don't fit at all
81	// are listed as omitted.
82	//
83	// FEAT-022 §1: large diffs degrade to stat + hunk-headers only.
84	func ClampDiff(diff string, max int) (clamped string, section EvidenceAssemblySection) {
85		section = EvidenceAssemblySection{Name: "diff"}
86		if len(diff) <= max {
87			section.BytesIncluded = len(diff)
88			return diff, section
89		}
90		files := DecomposeDiff(diff)
91		if len(files) == 0 {
92			out, truncated, orig := ClampOutput(diff, max)
93			section.BytesIncluded = len(out)
94			section.BytesOmitted = orig - len(out)
95			if truncated {
96				section.TruncationReason = "byte_cap"
97			}
98			return out, section
99		}
100	
101		var b strings.Builder
102		used := 0
103		reserve := len(TruncationMarker)
104		for _, f := range files {
105			// Try full body first.
106			if used+len(f.Body) <= max {
107				b.WriteString(f.Body)
108				used += len(f.Body)
109				section.SelectedItems = append(section.SelectedItems, f.Path)
110				continue
111			}
112			// Degrade: stat + hunk headers only.
113			degraded := degradedFile(f)
114			if used+len(degraded)+reserve <= max {
115				b.WriteString(degraded)
116				used += len(degraded)
117				section.SelectedItems = append(section.SelectedItems, f.Path)
118				section.BytesOmitted += len(f.Body) - len(degraded)
119				if section.TruncationReason == "" {
120					section.TruncationReason = "diff_degraded"
121				}
122				continue
123			}
124			// No room even for degraded form: omit.
125			section.OmittedItems = append(section.OmittedItems, f.Path)
126			section.BytesOmitted += len(f.Body)
127			if section.TruncationReason == "" {
128				section.TruncationReason = "byte_cap"
129			}
130		}
131		if section.BytesOmitted > 0 {
132			b.WriteString(TruncationMarker)
133		}
134		out := b.String()
135		section.BytesIncluded = len(out)
136		return out, section
137	}
138	
139	func degradedFile(f DiffFile) string {
140		var b strings.Builder
141		b.WriteString("diff --git a/")
142		b.WriteString(f.Path)
143		b.WriteString(" b/")
144		b.WriteString(f.Path)
145		b.WriteString("\n")
146		if f.Stat != "" {
147			b.WriteString(f.Stat)
148			b.WriteString("\n")
149		}
150		for _, h := range f.HunkHeaders {
151			b.WriteString(h)
152			b.WriteString("\n")
153		}
154		return b.String()
155	}
