5	// EvidenceAssemblySection is the per-section telemetry record produced by
6	// the evidence-assembly call sites and consumed by Stages C1, C2, and F
7	// (FEAT-022 §15). The shape is a contract — downstream stages decode this
8	// without re-deriving field names.
9	type EvidenceAssemblySection struct {
10		Name             string   `json:"name"`
11		BytesIncluded    int      `json:"bytes_included"`
12		BytesOmitted     int      `json:"bytes_omitted"`
13		TruncationReason string   `json:"truncation_reason"`
14		SelectedItems    []string `json:"selected_items"`
15		OmittedItems     []string `json:"omitted_items"`
16	}
17	
18	// SectionInput is one candidate section handed to FitSections, in
19	// caller-determined priority order (highest priority first).
20	type SectionInput struct {
21		Name    string
22		Content string
23		// MinFloor, when true, marks this section as part of the minimum
24		// evidence floor (FEAT-022 §5 items 1-2). Floor sections are always
25		// included; if even the floor exceeds budget FitSections still
26		// emits them but reports the overall overflow via the returned
27		// TotalBytes vs budget comparison left to the caller.
28		MinFloor bool
29		// PerSectionCap, if non-zero, additionally clamps this section to
30		// at most this many bytes (using ClampOutput) before budgeting.
31		PerSectionCap int
32	}
33	
34	// FitResult is the outcome of FitSections.
35	type FitResult struct {
36		Included   []SectionInput
37		Omitted    []SectionInput
38		TotalBytes int
39		Sections   []EvidenceAssemblySection
40	}
41	
42	// FitSections selects sections to include under a total byte budget,
43	// in priority order. Floor sections are always included. Non-floor
44	// sections are added in order while their content fits the remaining
45	// budget; sections that don't fit are recorded as omitted.
46	//
47	// Default behavior is line-based and type-agnostic (FEAT-022 §1):
48	// when a section's PerSectionCap is non-zero, content is clamped to
49	// that cap before budgeting. Markdown-aware extraction is handled by
50	// callers that need it; this primitive does not parse content.
51	func FitSections(sections []SectionInput, budget int) FitResult {
52		if budget < 0 {
53			budget = 0
54		}
55		res := FitResult{
56			Sections: make([]EvidenceAssemblySection, 0, len(sections)),
57		}
58		used := 0
59	
60		// First pass: include all floor sections (apply per-section cap).
61		for _, s := range sections {
62			if !s.MinFloor {
63				continue
64			}
65			content, reason := capContent(s)
66			section := EvidenceAssemblySection{
67				Name:          s.Name,
68				BytesIncluded: len(content),
69				BytesOmitted:  len(s.Content) - len(content),
70				SelectedItems: []string{s.Name},
71			}
72			if reason != "" {
73				section.TruncationReason = reason
74			}
75			used += len(content)
76			res.Included = append(res.Included, SectionInput{
77				Name: s.Name, Content: content, MinFloor: true,
78			})
79			res.Sections = append(res.Sections, section)
80		}
81	
82		// Second pass: non-floor in priority order, fit under remaining budget.
83		for _, s := range sections {
84			if s.MinFloor {
85				continue
86			}
87			content, reason := capContent(s)
88			remaining := budget - used
89			if len(content) <= remaining {
90				used += len(content)
91				res.Included = append(res.Included, SectionInput{
92					Name: s.Name, Content: content,
93				})
94				section := EvidenceAssemblySection{
95					Name:          s.Name,
96					BytesIncluded: len(content),
97					BytesOmitted:  len(s.Content) - len(content),
98					SelectedItems: []string{s.Name},
99				}
100				if reason != "" {
101					section.TruncationReason = reason
102				}
103				res.Sections = append(res.Sections, section)
104				continue
105			}
106			// Doesn't fit even at PerSectionCap — try line-trim to fit.
107			if remaining > 0 {
108				trimmed := trimToLineBudget(content, remaining-len(TruncationMarker))
109				if trimmed != "" {
110					body := trimmed + TruncationMarker
111					used += len(body)
112					res.Included = append(res.Included, SectionInput{
113						Name: s.Name, Content: body,
114					})
115					res.Sections = append(res.Sections, EvidenceAssemblySection{
116						Name:             s.Name,
117						BytesIncluded:    len(body),
118						BytesOmitted:     len(s.Content) - len(body),
119						TruncationReason: "budget",
120						SelectedItems:    []string{s.Name},
121					})
122					continue
123				}
124			}
125			// No room: omit entirely.
126			res.Omitted = append(res.Omitted, s)
127			res.Sections = append(res.Sections, EvidenceAssemblySection{
128				Name:             s.Name,
129				BytesIncluded:    0,
130				BytesOmitted:     len(s.Content),
131				TruncationReason: "budget",
132				OmittedItems:     []string{s.Name},
133			})
134		}
135		res.TotalBytes = used
136		return res
137	}
138	
139	func capContent(s SectionInput) (string, string) {
140		if s.PerSectionCap <= 0 || len(s.Content) <= s.PerSectionCap {
141			return s.Content, ""
142		}
143		clamped, truncated, _ := ClampOutput(s.Content, s.PerSectionCap)
144		if truncated {
145			return clamped, "per_section_cap"
146		}
147		return clamped, ""
148	}
149	
150	// trimToLineBudget returns the longest prefix of s, ending on a line
151	// boundary, whose length is at most budget. Returns "" if budget <= 0
152	// or the first line alone exceeds budget.
153	func trimToLineBudget(s string, budget int) string {
154		if budget <= 0 {
155			return ""
156		}
157		if len(s) <= budget {
158			return s
159		}
160		cut := strings.LastIndexByte(s[:budget], '\n')
161		if cut <= 0 {
162			return ""
163		}
164		return s[:cut+1]
165	}
