29	type Runner struct {
30		registry *harnessRegistry
31		Config   Config
32		Catalog  *Catalog     // model catalog for routing; defaults to BuiltinCatalog
33		Executor Executor     // injected; defaults to OSExecutor
34		LookPath LookPathFunc // injected; defaults to exec.LookPath
35	
36		// WorkDir is the project root used for loading native agent config.
37		WorkDir string
38	}
