40	// NewRunner creates a runner with defaults.
41	func NewRunner(cfg Config) *Runner {
42		if cfg.Harness == "" {
43			cfg.Harness = DefaultHarness
44		}
45		if cfg.TimeoutMS == 0 {
46			cfg.TimeoutMS = DefaultTimeoutMS
47		}
48		if cfg.WallClockMS == 0 {
49			cfg.WallClockMS = DefaultWallClockMS
50		}
51		if cfg.SessionLogDir == "" {
52			cfg.SessionLogDir = DefaultLogDir
53		}
54		// Build the effective catalog in precedence order (lowest to highest priority):
55		//   1. Built-in seed (DefaultModelCatalogYAML — deterministic fallback for smart/standard/cheap)
56		//   2. Shared ddx-agent catalog (~/.config/agent/models.yaml — authoritative when installed)
57		//   3. User overrides (~/.ddx/model-catalog.yaml — user wins over shared and built-in)
58		catalog := BuiltinCatalog.Clone()
59		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
60			ApplyCatalogFromService(context.Background(), catalog, svc)
61		}
62		if path := DefaultModelCatalogPath(); path != "" {
63			if yml, err := LoadModelCatalogYAML(path); err == nil && yml != nil {
64				ApplyModelCatalogYAML(catalog, yml)
65			}
66		}
67	
68		r := &Runner{
69			registry: newHarnessRegistry(),
70			Config:   cfg,
71			Catalog:  catalog,
72			Executor: &OSExecutor{},
73			LookPath: DefaultLookPath,
74		}
75		r.registry.LookPath = func(file string) (string, error) {
76			if r.LookPath != nil {
77				return r.LookPath(file)
78			}
79			return DefaultLookPath(file)
80		}
81		return r
82	}
