277	func captureGitDiff(worktreePath string) string {
278		cmd := internalgit.Command(context.Background(), worktreePath, "diff", "HEAD")
279		out, err := cmd.Output()
280		if err != nil {
281			return ""
282		}
283		diff := string(out)
284	
285		cmd3 := internalgit.Command(context.Background(), worktreePath, "ls-files", "--others", "--exclude-standard")
286		untrackedOut, _ := cmd3.Output()
287		untracked := strings.TrimSpace(string(untrackedOut))
288		if untracked != "" {
289			for _, f := range strings.Split(untracked, "\n") {
290				f = strings.TrimSpace(f)
291				if f == "" {
292					continue
293				}
294				content, err := os.ReadFile(filepath.Join(worktreePath, f))
295				if err != nil {
296					continue
297				}
298				diff += fmt.Sprintf("\n--- /dev/null\n+++ b/%s\n@@ -0,0 +1 @@\n", f)
299				for _, line := range strings.Split(string(content), "\n") {
300					if line != "" || len(content) > 0 {
301						diff += "+" + line + "\n"
302					}
303				}
304			}
305		}
306		return strings.TrimSpace(diff)
307	}
