316	// cleanupCompareWorktrees removes the worktrees created for a compare run.
317	// Free function; both RunCompareViaService and RunCompareWithAgent route through
318	// this helper.
319	func cleanupCompareWorktrees(repoDir, compareID string) {
320		if root, err := resolveGitRoot(repoDir); err == nil {
321			repoDir = root
322		}
323		wtBase := filepath.Join(repoDir, ".worktrees")
324		entries, err := os.ReadDir(wtBase)
325		if err != nil {
326			return
327		}
328		for _, e := range entries {
329			if e.IsDir() && strings.HasPrefix(e.Name(), compareID) {
330				wtPath := filepath.Join(wtBase, e.Name())
331				cmd := internalgit.Command(context.Background(), repoDir, "worktree", "remove", "--force", wtPath)
332				_ = cmd.Run()
333			}
334		}
335		cmd := internalgit.Command(context.Background(), repoDir, "worktree", "prune")
336		_ = cmd.Run()
337	}
