345	// RunQuorumWith invokes multiple harnesses concurrently and returns each
346	// result. Production callers should use RunQuorumViaService; tests may pass
347	// Runner.Run.
348	func RunQuorumWith(run RunFunc, opts QuorumOptions) ([]*Result, error) {
349		if len(opts.Harnesses) == 0 {
350			return nil, fmt.Errorf("agent: quorum requires at least one harness")
351		}
352	
353		threshold := effectiveThreshold(opts.Strategy, opts.Threshold, len(opts.Harnesses))
354		if threshold < 1 || threshold > len(opts.Harnesses) {
355			return nil, fmt.Errorf("agent: invalid quorum threshold %d for %d harnesses", threshold, len(opts.Harnesses))
356		}
357	
358		results := make([]*Result, len(opts.Harnesses))
359		var wg sync.WaitGroup
360		var mu sync.Mutex
361		var firstErr error
362	
363		for i, name := range opts.Harnesses {
364			wg.Add(1)
365			go func(idx int, harness string) {
366				defer wg.Done()
367				runOpts := opts.RunOptions
368				runOpts.Harness = harness
369				result, err := run(runOpts)
370				mu.Lock()
371				if err != nil && firstErr == nil {
372					firstErr = err
373				}
374				results[idx] = result
375				mu.Unlock()
376			}(i, name)
377		}
378		wg.Wait()
379	
380		return results, firstErr
381	}
