399	// QuorumMet returns true if enough results succeeded.
400	func QuorumMet(strategy string, threshold int, results []*Result) bool {
401		total := len(results)
402		eff := effectiveThreshold(strategy, threshold, total)
403		successes := 0
404		for _, r := range results {
405			if r != nil && r.ExitCode == 0 {
406				successes++
407			}
408		}
409		return successes >= eff
410	}
411	
412	func effectiveThreshold(strategy string, threshold, total int) int {
413		switch strategy {
414		case "any":
415			return 1
416		case "majority":
417			return (total / 2) + 1
418		case "unanimous":
419			return total
420		default:
421			if threshold > 0 {
422				return threshold
423			}
424			return 1
425		}
426	}
