561	// RunBenchmarkWith executes all prompts in a suite against all arms via the
562	// runCompare closure. Production callers should use RunBenchmarkViaService.
563	func RunBenchmarkWith(runCompare func(CompareOptions) (*ComparisonRecord, error), suite *BenchmarkSuite) (*BenchmarkResult, error) {
564		result := &BenchmarkResult{
565			Suite:     suite.Name,
566			Version:   suite.Version,
567			Timestamp: time.Now().UTC(),
568			Arms:      suite.Arms,
569		}
570	
571		var timeout time.Duration
572		if suite.Timeout != "" {
573			var err error
574			timeout, err = time.ParseDuration(suite.Timeout)
575			if err != nil {
576				return nil, fmt.Errorf("invalid timeout %q: %w", suite.Timeout, err)
577			}
578		}
579	
580		for _, prompt := range suite.Prompts {
581			promptText := prompt.Prompt
582			if promptText == "" && prompt.PromptFile != "" {
583				data, err := readPromptFileBounded(prompt.PromptFile)
584				if err != nil {
585					return nil, fmt.Errorf("reading prompt file %s: %w", prompt.PromptFile, err)
586				}
587				promptText = string(data)
588			}
589	
590			baseOpts := RunOptions{
591				Prompt:  promptText,
592				Timeout: timeout,
593			}
594	
595			compareOpts := BenchmarkArmsToCompare(suite.Arms, baseOpts)
596			compareOpts.Sandbox = suite.Sandbox
597			compareOpts.PostRun = suite.PostRun
598	
599			record, err := runCompare(compareOpts)
600			if err != nil {
601				return nil, fmt.Errorf("prompt %s: %w", prompt.ID, err)
602			}
603	
604			result.Comparisons = append(result.Comparisons, *record)
605		}
606	
607		result.Summary = benchSummarize(result)
608		return result, nil
609	}
