411	func evidItoa(i int) string {
412		if i == 0 {
413			return "0"
414		}
415		neg := false
416		if i < 0 {
417			neg = true
418			i = -i
419		}
420		var buf [20]byte
421		pos := len(buf)
422		for i > 0 {
423			pos--
424			buf[pos] = byte('0' + i%10)
425			i /= 10
426		}
427		out := string(buf[pos:])
428		if neg {
429			return "-" + out
430		}
431		return out
432	}
